var startDate = (msg.req && msg.req.query && msg.req.query.startDate || '').toString().trim();
var endDate = (msg.req && msg.req.query && msg.req.query.endDate || '').toString().trim();
var criticalThreshold = parseFloat(msg.req && msg.req.query && msg.req.query.criticalThreshold) || 10000000;

// Generar UUID
var uuid = (
  Date.now().toString(36).toUpperCase().slice(-4) +
  Math.random().toString(36).substring(2, 6).toUpperCase() +
  Math.random().toString(36).substring(2, 6).toUpperCase()
);

// Default: mes actual
if (!startDate || !endDate) {
  var now = new Date();
  var y = now.getFullYear();
  var m = String(now.getMonth() + 1).padStart(2, '0');
  var lastDay = new Date(y, now.getMonth() + 1, 0).getDate();
  startDate = y + m + '01';
  endDate = y + m + String(lastDay).padStart(2, '0');
}

// Validar formato
if (!/^\d{8}$/.test(startDate) || !/^\d{8}$/.test(endDate)) {
  msg.statusCode = 400;
  msg.payload = { error: 'Formato inválido. Use YYYYMMDD' };
  return msg;
}
if (endDate < startDate) {
  msg.statusCode = 400;
  msg.payload = { error: 'endDate debe ser >= startDate' };
  return msg;
}

// Guardar metadata
msg._trace = {
  uuid: uuid,
  startDate: startDate,
  endDate: endDate,
  criticalThreshold: criticalThreshold
};

// La SQL está hardcodeada en el nodo MSSQL con fechas dinámicas T-SQL.
// También intentamos msg.query por si el nodo lo soporta:
msg.query = 'SELECT' +
  ' V_EZI_CUENTAS.CODIGO,' +
  ' V_EZI_CUENTAS.DESCRIPCION AS CUENTA,' +
  ' V_EZI_CUENTAS.CRubro,' +
  ' V_EZI_CUENTAS.NRubro,' +
  ' V_EZI_CUENTAS.CSubrubro1,' +
  ' V_EZI_CUENTAS.NSubrubro1,' +
  ' V_EZI_CUENTAS.CSubrubro2,' +
  ' V_EZI_CUENTAS.NSubrubro2,' +
  ' V_EZI_CUENTAS.CSubrubro3,' +
  ' V_EZI_CUENTAS.NSubrubro3,' +
  ' SUM(V_VALOR_.IMPORTE) AS DEBE_PERIODO,' +
  ' SUM(V_VALOR_1.IMPORTE) AS HABER_PERIODO,' +
  ' SUM(V_VALOR_.IMPORTE) - SUM(V_VALOR_1.IMPORTE) AS SALDO_PERIODO' +
' FROM V_TRCONTABLE_' +
' INNER JOIN V_ITEMCONTABLE_ ON V_TRCONTABLE_.ITEMSTRANSACCION_ID = V_ITEMCONTABLE_.BO_PLACE_ID' +
' INNER JOIN V_VALOR_ ON V_ITEMCONTABLE_.DEBE_ID = V_VALOR_.ID' +
' INNER JOIN V_VALOR_ AS V_VALOR_1 ON V_ITEMCONTABLE_.HABER_ID = V_VALOR_1.ID' +
' INNER JOIN V_EZI_CUENTAS ON V_ITEMCONTABLE_.REFERENCIA_ID = V_EZI_CUENTAS.ID' +
' WHERE SUBSTRING(V_TRCONTABLE_.FECHAAPLICACION,1,8) >= ''' + startDate + ''' +
  ' AND SUBSTRING(V_TRCONTABLE_.FECHAAPLICACION,1,8) <= ''' + endDate + '''' +
  ' AND V_EZI_CUENTAS.CODIGO BETWEEN ''0'' AND ''9''' +
  ' AND V_TRCONTABLE_.ESTADO = ''C''' +
' GROUP BY' +
    ' V_EZI_CUENTAS.CODIGO, V_EZI_CUENTAS.DESCRIPCION,' +
    ' V_EZI_CUENTAS.CRubro, V_EZI_CUENTAS.NRubro,' +
