  return msg;
}

if (typeof rows === 'object' && !Array.isArray(rows)) {
  // Podría ser un objeto con error
  node.warn('[SumasSaldos] MSSQL respuesta inesperada: ' + JSON.stringify(rows).substring(0,200));
  if (rows.code || rows.message) {
    msg.statusCode = 500;
    msg.payload = { error: 'Error MSSQL: ' + (rows.message || rows.code) };
    return msg;
  }
}

if (!Array.isArray(rows) || rows.length === 0) {
  node.warn('[SumasSaldos] Sin datos en el período ' + startDate + '-' + endDate);
  msg.payload = buildEmptyResponse(startDate, endDate, trace.uuid);
  return msg;
}

node.warn('[SumasSaldos] OK - ' + rows.length + ' cuentas recibidas');

// Mapear cada fila
var sumasSaldos = [];
for (var i = 0; i < rows.length; i++) {
  var row = rows[i];
  var debe = parseFloat(row.DEBE_PERIODO) || 0;
  var haber = parseFloat(row.HABER_PERIODO) || 0;
  var saldo = debe - haber;
  var absSaldo = Math.abs(saldo);

  var estado = 'ok';
  if (absSaldo >= criticalThreshold) { estado = 'crit'; }
  else if (absSaldo >= criticalThreshold * 0.6) { estado = 'warn'; }

  sumasSaldos.push({
    codigo: row.CODIGO || '',
    cuenta: row.CUENTA || '',
    rubro: row.NRubro || '',
    ultMov: row.FECHA_ULT_MOV || '',
    subrubro: row.NSubrubro1 || '',
    debeAcum: debe,
    haberAcum: haber,
    saldo: saldo,
    variacion: 0,
    estado: estado
  });
}

// KPIs
var totalDebe = 0, totalHaber = 0;
var critCount = 0, warnCount = 0;
for (var i = 0; i < sumasSaldos.length; i++) {
  var r = sumasSaldos[i];
  totalDebe += r.debeAcum;
  totalHaber += r.haberAcum;
  if (r.estado === 'crit') critCount++;
  else if (r.estado === 'warn') warnCount++;
}

// Alertas
var alertas = [];
for (var i = 0; i < sumasSaldos.length; i++) {
  var r = sumasSaldos[i];
  if (r.estado === 'crit') {
    alertas.push({ type: 'critical', title: 'Crítica: ' + r.cuenta, desc: 'Saldo: $' + r.saldo.toLocaleString('es-AR') + ' | ' + r.codigo });
  } else if (r.estado === 'warn') {
    alertas.push({ type: 'warning', title: 'Atención: ' + r.cuenta, desc: 'Saldo: $' + r.saldo.toLocaleString('es-AR') + ' supera umbral' });
  }
}

// Evolución desde datos
var evolucion = buildEvolucion(sumasSaldos);

// Response
msg.payload = {
  sumasSaldos: sumasSaldos,
  mayor: [], libroDiario: [], imputaciones: [],
  egresos: [], ingresos: [],
  proveedoresSaldos: [], proveedoresPendientes: [], interempresas: [],
  evolucion: evolucion,
  alertas: alertas,
  _metadata: {
    uuid: trace.uuid || 'N/A',
    source: 'node-red',
    startDate: startDate,
    endDate: endDate,
    totalCuentas: sumasSaldos.length,
    totalDebe: totalDebe,
    totalHaber: totalHaber,
    saldoTotal: totalDebe - totalHaber,
    cuentasCriticas: critCount,
    cuentasAdvertencia: warnCount,
    timestamp: new Date().toISOString()
  }
};

return msg;

// ---- Helper ----
function buildEmptyResponse(sd, ed, uid) {
  return {
    sumasSaldos: [],
    mayor: [], libroDiario: [], imputaciones: [],
    egresos: [], ingresos: [],
    proveedoresSaldos: [], proveedoresPendientes: [], interempresas: [],
    evolucion: { labels: [], caja: [], ventas: [], costos: [] },
    alertas: [{ type: 'info', title: 'Sin datos en el período', desc: 'No hay registros entre ' + sd + ' y ' + ed }],
    _metadata: {
      uuid: uid || 'N/A', source: 'node-red',
      startDate: sd, endDate: ed,
      totalCuentas: 0, totalDebe: 0, totalHaber: 0, saldoTotal: 0,
      cuentasCriticas: 0, cuentasAdvertencia: 0,
      timestamp: new Date().toISOString()
    }
  };
}

function buildEvolucion(accounts) {
  var grupos = {};
  var nombres = { '1': 'Activo', '2': 'Pasivo', '3': 'Patrimonio', '4': 'Ingresos', '5': 'Egresos' };
  for (var i = 0; i < accounts.length; i++) {
    var prefijo = (accounts[i].codigo || '0').charAt(0);
    var name = nombres[prefijo] || 'Otros';
    grupos[name] = (grupos[name] || 0) + Math.abs(accounts[i].saldo);
  }
  var labels = [], values = [];
  var keys = Object.keys(grupos);
  for (var i = 0; i < keys.length; i++) {
    if (grupos[keys[i]] > 0) { labels.push(keys[i]); values.push(grupos[keys[i]]); }
  }
  if (labels.length === 0) { return { labels: ['Sin datos'], caja: [0], ventas: [0], costos: [0] }; }
  return { labels: labels, caja: values, ventas: [], costos: [] };
}

